// #65L slice 3 — C++ parity comparator for RF-DETR backbone.
//
// Loads the per-stage Python reference dumps generated by
// `/tmp/yolocpp_parity/dump_rfdetr_forward.py` (env-gated via
// `RFDETR_PARITY_DUMP_DIR=/tmp/yolocpp_parity/dumps/rfdetr_base`),
// runs the C++ backbone forward with the same `rf-detr-base.pth`
// weights on the same input, and reports per-stage max-absolute-diff.
//
// Bisects the architecture: the FIRST stage with non-trivial diff
// is the next parity bug to chase. SKIP-gated when the dump
// directory is absent.

#include <cstdlib>
#include <filesystem>
#include <fstream>
#include <iostream>
#include <sstream>
#include <string>
#include <vector>

#include <torch/torch.h>

#include "yolocpp/models/rfdetr.hpp"
#include "yolocpp/models/rfdetr_backbone.hpp"
#include "yolocpp/models/rfdetr_projector.hpp"
#include "yolocpp/serialization/pt_loader.hpp"
#include "yolocpp/serialization/rfdetr_weights.hpp"

namespace fs = std::filesystem;

namespace {

torch::Tensor load_dump(const fs::path& dir, const std::string& name) {
  fs::path bin = dir / (name + ".bin");
  fs::path shape_p = dir / (name + ".shape");
  if (!fs::exists(bin) || !fs::exists(shape_p)) return {};
  std::ifstream f_shape(shape_p);
  std::stringstream ss; ss << f_shape.rdbuf();
  std::vector<int64_t> shape;
  int64_t v; while (ss >> v) shape.push_back(v);
  int64_t numel = 1;
  for (auto s : shape) numel *= s;
  std::vector<float> buf(numel);
  std::ifstream f_bin(bin, std::ios::binary);
  f_bin.read(reinterpret_cast<char*>(buf.data()), numel * sizeof(float));
  auto t = torch::from_blob(buf.data(), shape, torch::kFloat).clone();
  return t;
}

float max_abs_diff(const torch::Tensor& a, const torch::Tensor& b) {
  if (a.sizes() != b.sizes()) return std::numeric_limits<float>::infinity();
  return (a - b).abs().max().item<float>();
}

}  // namespace

int main() {
  const char* dir = std::getenv("RFDETR_PARITY_DUMP_DIR");
  if (!dir || !fs::is_directory(dir)) {
    std::cout << "SKIP: RFDETR_PARITY_DUMP_DIR not set or not a directory\n";
    return 0;
  }
  fs::path d(dir);
  auto inp = load_dump(d, "input");
  if (!inp.defined()) {
    std::cout << "SKIP: input.bin missing in " << dir << "\n";
    return 0;
  }
  std::cout << "input shape: " << inp.sizes() << "\n";

  // Build base model + load weights.
  yolocpp::models::RFDetr m(yolocpp::models::kRfdetrBase, /*nc=*/80);
  m->eval();
  const char* w = std::getenv("RFDETR_TEST_WEIGHTS_DIR");
  if (!w) {
    std::cout << "SKIP: RFDETR_TEST_WEIGHTS_DIR not set\n";
    return 0;
  }
  fs::path wpath = fs::path(w) / "rf-detr-base.pth";
  if (!fs::exists(wpath)) {
    std::cout << "SKIP: " << wpath << " missing\n";
    return 0;
  }
  m->load_from_upstream_pt(wpath.string(), /*strict=*/false);

  // Walk the live module tree to find the inner Dinov2Model so we
  // can call `embeddings()` and `encoder.forward_all_blocks()`
  // directly — bypassing forward_eval to capture per-stage
  // activations alongside Python's dumps.
  torch::NoGradGuard ng;
  auto& slot = *m->named_children()["backbone"]->as<torch::nn::ModuleListImpl>();
  auto& bs   = *slot[0]->as<yolocpp::models::rfdetr::BackboneSlotImpl>();
  auto& wrapper = *bs.encoder.ptr();          // Dinov2Wrapper
  auto& dmodel  = *wrapper.encoder.ptr();     // Dinov2Model

  // Sanity: verify position_embeddings parameter (the source of the
  // 0.0063 diff) is bit-equal to what `load_flat_state_dict` sees.
  {
    auto sd = yolocpp::serialization::load_flat_state_dict(
        wpath.string(), "model");
    for (auto& [k, t] : sd.entries) {
      if (k == "backbone.0.encoder.encoder.embeddings.position_embeddings") {
        float diff = max_abs_diff(
            dmodel.embeddings->position_embeddings.to(torch::kFloat).contiguous(),
            t.to(torch::kFloat).contiguous());
        std::cout << "[probe] position_embeddings  shape="
                  << dmodel.embeddings->position_embeddings.sizes()
                  << "  loaded_max_abs_diff=" << diff << "\n";
        break;
      }
    }
  }

  // Compare custom bicubic vs libtorch::interpolate vs the Python
  // reference saved at /tmp/yolocpp_parity/dumps/bicubic_probe/.
  {
    fs::path probe_dir("/tmp/yolocpp_parity/dumps/bicubic_probe");
    if (fs::exists(probe_dir / "x.bin") &&
        fs::exists(probe_dir / "py_out.bin")) {
      // Manually load the [1, 4, 37, 37] x and [1, 4, 40, 40] py_out.
      std::vector<float> xbuf(1 * 4 * 37 * 37);
      std::ifstream(probe_dir / "x.bin", std::ios::binary)
          .read(reinterpret_cast<char*>(xbuf.data()), xbuf.size() * 4);
      std::vector<float> pbuf(1 * 4 * 40 * 40);
      std::ifstream(probe_dir / "py_out.bin", std::ios::binary)
          .read(reinterpret_cast<char*>(pbuf.data()), pbuf.size() * 4);
      auto x_t = torch::from_blob(xbuf.data(), {1, 4, 37, 37},
                                    torch::kFloat).clone();
      auto py_t = torch::from_blob(pbuf.data(), {1, 4, 40, 40},
                                    torch::kFloat).clone();
      auto custom = yolocpp::models::rfdetr::bicubic_interpolate_2d_export(
          x_t, 40, 40);
      auto libt = torch::nn::functional::interpolate(
          x_t, torch::nn::functional::InterpolateFuncOptions()
                  .size(std::vector<int64_t>{40, 40})
                  .mode(torch::kBicubic)
                  .align_corners(false));
      std::cout << "[bicubic-probe] custom vs Python   max_abs_diff="
                << max_abs_diff(custom, py_t) << "\n";
      std::cout << "[bicubic-probe] libtorch vs Python max_abs_diff="
                << max_abs_diff(libt,   py_t) << "\n";
      std::cout << "[bicubic-probe] custom vs libtorch max_abs_diff="
                << max_abs_diff(custom, libt) << "\n";
    }
    // Real position-embedding patch slice probe (the actual input
    // that gets fed to bicubic inside the embeddings forward).
    if (fs::exists(probe_dir / "pe_patch_input.bin") &&
        fs::exists(probe_dir / "pe_patch_output_sf.bin")) {
      std::vector<float> ibuf(1 * 384 * 37 * 37);
      std::ifstream(probe_dir / "pe_patch_input.bin", std::ios::binary)
          .read(reinterpret_cast<char*>(ibuf.data()), ibuf.size() * 4);
      std::vector<float> obuf(1 * 384 * 40 * 40);
      std::ifstream(probe_dir / "pe_patch_output_sf.bin", std::ios::binary)
          .read(reinterpret_cast<char*>(obuf.data()), obuf.size() * 4);
      auto i_t = torch::from_blob(ibuf.data(), {1, 384, 37, 37},
                                    torch::kFloat).clone();
      auto o_py = torch::from_blob(obuf.data(), {1, 384, 40, 40},
                                    torch::kFloat).clone();
      // Compare the C++-extracted patch slice to Python's identical
      // extraction.
      auto pe_param = dmodel.embeddings->position_embeddings;
      auto pat_cpp  = pe_param.slice(1, 1).contiguous()
                        .view({1, 37, 37, 384})
                        .permute({0, 3, 1, 2}).contiguous();
      std::cout << "[pe-input-probe] cpp slice vs Python slice "
                << "max_abs_diff=" << max_abs_diff(pat_cpp, i_t) << "\n";
      auto custom_o = yolocpp::models::rfdetr::bicubic_interpolate_2d_export(
          pat_cpp, 40, 40);
      std::cout << "[pe-bicubic-probe] custom vs Python out "
                << "max_abs_diff=" << max_abs_diff(custom_o, o_py) << "\n";
    }
  }

  // Embeddings sub-stage bisection.
  auto stages = dmodel.embeddings->forward_stages(inp);
  auto report_stage = [&](const std::string& name, const torch::Tensor& cpp_t) {
    auto py_t = load_dump(d, name);
    if (!py_t.defined()) {
      std::cout << "[stage] " << name << "  C++ shape=" << cpp_t.sizes()
                << "  (no Py dump)\n";
      return;
    }
    float diff = max_abs_diff(cpp_t.to(torch::kFloat).contiguous(),
                                py_t.to(torch::kFloat).contiguous());
    std::cout << "[stage] " << std::left << name
              << "  shape=" << cpp_t.sizes()
              << "  max_abs_diff=" << diff << "\n";
  };
  report_stage("emb_step1_patch",     stages.patch);
  report_stage("emb_step2_with_cls",  stages.with_cls);
  report_stage("emb_step3_pos_embed", stages.pos_embed);
  // Bisect inside emb_step3: cls vs patch portions separately.
  {
    auto py_t = load_dump(d, "emb_step3_pos_embed");
    if (py_t.defined()) {
      auto cls_cpp = stages.pos_embed.slice(1, 0, 1);
      auto cls_py  = py_t.slice(1, 0, 1);
      auto pat_cpp = stages.pos_embed.slice(1, 1);
      auto pat_py  = py_t.slice(1, 1);
      std::cout << "[bisect emb_step3] cls    max_abs_diff="
                << max_abs_diff(cls_cpp, cls_py) << "\n";
      std::cout << "[bisect emb_step3] patch  max_abs_diff="
                << max_abs_diff(pat_cpp, pat_py) << "\n";
    }
  }
  report_stage("emb_step4_with_pos",  stages.with_pos);
  report_stage("embeddings_out",      stages.windowed);
  auto emb_cpp = stages.windowed;

  auto blocks = dmodel.encoder->forward_all_blocks(emb_cpp);
  for (size_t i = 0; i < blocks.size(); ++i) {
    char name[32]; std::snprintf(name, sizeof(name), "layer%02zu_out", i);
    auto py = load_dump(d, name);
    if (!py.defined()) continue;
    float diff = max_abs_diff(blocks[i].to(torch::kFloat).contiguous(),
                                py.to(torch::kFloat).contiguous());
    std::cout << "[stage] " << name << "  shape="
              << blocks[i].sizes() << "  max_abs_diff=" << diff << "\n";
  }

  // ── Backbone+projector → transformer intermediates ──
  std::cout << "\n--- transformer-stage diffs ---\n";
  auto& slot_inner = bs;   // BackboneSlotImpl
  auto memory_2d = slot_inner.forward(inp);   // [B, hidden, Hg, Wg]
  {
    auto py = load_dump(d, "backbone_feat_0");
    if (py.defined()) {
      float diff = max_abs_diff(memory_2d.to(torch::kFloat).contiguous(),
                                  py.to(torch::kFloat).contiguous());
      std::cout << "[stage] backbone_feat_0   shape="
                << memory_2d.sizes() << "  max_abs_diff=" << diff
                << "  cpp_sum=" << memory_2d.sum().item<float>()
                << "  py_sum="  << py.sum().item<float>() << "\n";
    }
  }
  // Run the full transformer + heads, then compare against upstream.
  {
    int Q = m->scale.num_queries;
    auto qfeat = m->named_parameters()["query_feat.weight"]
                      .slice(0, 0, Q);
    auto rpemb = m->named_parameters()["refpoint_embed.weight"]
                      .slice(0, 0, Q);
    auto tf_out = m->named_modules()["transformer"]
                      ->as<yolocpp::models::rfdetr::RFDetrTransformerImpl>()
                      ->forward(memory_2d, qfeat, rpemb, Q);
    // Bisect inside decoder layer 0.
    {
      auto& trans = *m->named_modules()["transformer"]
                       ->as<yolocpp::models::rfdetr::RFDetrTransformerImpl>();
      auto memory = memory_2d.flatten(2).transpose(1, 2).contiguous();
      // Reproduce two-stage init:
      auto props = yolocpp::models::rfdetr::gen_encoder_output_proposals_1l(
          memory, memory_2d.size(2), memory_2d.size(3));
      auto out_mem = trans.enc_output_norm[0]->as<torch::nn::LayerNormImpl>()
                       ->forward(trans.enc_output[0]->as<torch::nn::LinearImpl>()
                                       ->forward(props.output_memory));
      auto cls_l = trans.enc_out_class_embed[0]->as<torch::nn::LinearImpl>()
                       ->forward(out_mem);
      auto bbox_d = trans.enc_out_bbox_embed[0]->as<yolocpp::models::rfdetr::RFDetrMLPImpl>()
                       ->forward(out_mem);
      auto coord_xy = bbox_d.slice(-1, 0, 2) * props.output_proposals.slice(-1, 2, 4) + props.output_proposals.slice(-1, 0, 2);
      auto coord_wh = bbox_d.slice(-1, 2, 4).exp() * props.output_proposals.slice(-1, 2, 4);
      auto coord = torch::cat({coord_xy, coord_wh}, -1);
      auto scores = std::get<0>(cls_l.max(-1));
      int K = Q;
      auto idx = std::get<1>(scores.topk(K, 1));
      auto idx4 = idx.unsqueeze(-1).expand({1, K, 4});
      auto rp_ts = torch::gather(coord, 1, idx4);
      auto subset = rpemb.unsqueeze(0).expand({1, K, 4}).contiguous();
      auto rp_xy = subset.slice(-1, 0, 2) * rp_ts.slice(-1, 2, 4) + rp_ts.slice(-1, 0, 2);
      auto rp_wh = subset.slice(-1, 2, 4).exp() * rp_ts.slice(-1, 2, 4);
      auto refpts = torch::cat({rp_xy, rp_wh}, -1);
      std::cout << "[dec_l0] refpts cpp_sum=" << refpts.sum().item<float>()
                << " abs.max=" << refpts.abs().max().item<float>() << "\n";
      auto tgt0 = qfeat.unsqueeze(0).expand({1, K, qfeat.size(-1)}).contiguous();
      // Compute query_pos via ref_point_head.
      auto sin_emb = yolocpp::models::rfdetr::gen_sineembed_for_position(
          refpts, /*dim=*/static_cast<int>(memory.size(-1)) / 2);
      auto query_pos = trans.decoder->ref_point_head->forward(sin_emb);
      // Decoder layer 0 forward.
      auto& l0 = *trans.decoder->layers[0]
                      ->as<yolocpp::models::rfdetr::RFDetrDecoderLayerImpl>();
      auto stages_l0 = l0.forward_stages(tgt0, query_pos, refpts, memory,
                                            memory_2d.size(2), memory_2d.size(3));

      auto report = [&](const std::string& name, const torch::Tensor& cpp_t) {
        auto py_t = load_dump(d, name);
        if (!py_t.defined()) {
          std::cout << "[dec_l0] " << name << " (no Py dump)\n";
          return;
        }
        // Some Python dumps come out as tuples (`_0` suffix added);
        // try that fallback name too.
        if (py_t.sizes() != cpp_t.sizes()) {
          auto alt = load_dump(d, name + "_0");
          if (alt.defined() && alt.sizes() == cpp_t.sizes()) py_t = alt;
        }
        float diff = max_abs_diff(cpp_t.to(torch::kFloat).contiguous(),
                                    py_t.to(torch::kFloat).contiguous());
        std::cout << "[dec_l0] " << name << "  cpp_sum="
                  << cpp_t.sum().item<float>()
                  << "  py_sum=" << py_t.sum().item<float>()
                  << "  max_abs_diff=" << diff << "\n";
      };
      report("ref_point_head_out", query_pos);
      report("dec_l0_self_attn_out", stages_l0.self_attn_out);
      report("dec_l0_norm1_out",     stages_l0.norm1_out);
      report("dec_l0_cross_attn_out", stages_l0.cross_attn_out);
      report("dec_l0_norm2_out",     stages_l0.norm2_out);
      report("dec_l0_linear1_out",   stages_l0.linear1_out);
      report("dec_l0_linear2_out",   stages_l0.linear2_out);
      report("dec_l0_norm3_out",     stages_l0.norm3_out);
      // Compare the two-stage selected refpoints — likely source of
      // ref_point_head divergence.
      auto rp_ts_py = load_dump(d, "topk_refpts");
      if (rp_ts_py.defined() && rp_ts_py.sizes() == rp_ts.sizes()) {
        std::cout << "[dec_l0] topk_refpts  cpp_sum=" << rp_ts.sum().item<float>()
                  << "  py_sum=" << rp_ts_py.sum().item<float>()
                  << "  max_abs_diff="
                  << max_abs_diff(rp_ts, rp_ts_py) << "\n";
      }
      // Raw enc_output[0] (before norm) — Python hook captures before norm.
      auto raw_eo0 = trans.enc_output[0]->as<torch::nn::LinearImpl>()
                       ->forward(props.output_memory);
      report("enc_output0_out", raw_eo0);
      report("enc_output_norm0_out", out_mem);
      // Compare cls_l (raw enc_out_class[0]) vs Python.
      report("enc_out_class0_out", cls_l);
      // Probe whether my cls_l contains inf/nan.
      auto isfin = torch::isfinite(cls_l).all().item<bool>();
      auto cls_l_max = cls_l.max().item<float>();
      auto cls_l_min = cls_l.min().item<float>();
      std::cout << "[dec_l0] cls_l finite=" << (isfin ? "yes" : "NO!")
                << "  min=" << cls_l_min << "  max=" << cls_l_max << "\n";
      // Check the weight + bias.
      auto& cls0_w = m->named_parameters()["transformer.enc_out_class_embed.0.weight"];
      auto& cls0_b = m->named_parameters()["transformer.enc_out_class_embed.0.bias"];
      std::cout << "[probe] enc_out_class_embed.0.weight  abs.max="
                << cls0_w.abs().max().item<float>()
                << "  bias.abs.max=" << cls0_b.abs().max().item<float>() << "\n";
      report("enc_out_bbox0_out",  bbox_d);
    }
    std::cout << "[stage] transformer.decoder_out  shape="
              << tf_out.decoder_out.sizes()
              << "  cpp_sum=" << tf_out.decoder_out.sum().item<float>() << "\n";
    auto py_dec = load_dump(d, "dec_norm_out");
    if (py_dec.defined()) {
      float diff = max_abs_diff(tf_out.decoder_out.to(torch::kFloat).contiguous(),
                                  py_dec.to(torch::kFloat).contiguous());
      std::cout << "[stage]                Py "
                << py_dec.sizes() << " sum=" << py_dec.sum().item<float>()
                << "  →  max_abs_diff=" << diff << "\n";
    }
    // Final cls + bbox head outputs.
    auto cls_logits = m->named_modules()["class_embed"]
                          ->as<torch::nn::LinearImpl>()
                          ->forward(tf_out.decoder_out);
    std::cout << "[stage] class_embed_out  shape="
              << cls_logits.sizes()
              << "  cpp_sum=" << cls_logits.sum().item<float>()
              << "  abs.max=" << cls_logits.abs().max().item<float>() << "\n";
    // Top-K cls scores.
    auto cls_sigmoid = torch::sigmoid(cls_logits);   // [1, 300, 91]
    auto top_per_query = std::get<0>(cls_sigmoid.max(-1));
    auto top_K = top_per_query.topk(10);
    auto vals = std::get<0>(top_K).contiguous();
    std::cout << "[probe] top-10 cls scores:";
    for (int i = 0; i < 10; ++i)
        std::cout << " " << vals.flatten()[i].item<float>();
    std::cout << "\n";
    std::cout << "[probe] cls_logits min/max: "
              << cls_logits.min().item<float>() << " / "
              << cls_logits.max().item<float>() << "\n";
    // Verify class_embed weights loaded properly.
    auto& cls_w = m->named_parameters()["class_embed.weight"];
    auto& cls_b = m->named_parameters()["class_embed.bias"];
    std::cout << "[probe] class_embed.weight  shape=" << cls_w.sizes()
              << "  sum=" << cls_w.sum().item<float>()
              << "  abs.max=" << cls_w.abs().max().item<float>() << "\n";
    std::cout << "[probe] class_embed.bias    shape=" << cls_b.sizes()
              << "  sum=" << cls_b.sum().item<float>()
              << "  abs.max=" << cls_b.abs().max().item<float>() << "\n";
    // Verify decoder_out vs py.
    auto py_dec_out = load_dump(d, "transformer_out_2");  // [1, 300, 256] = memory_ts
    if (!py_dec_out.defined()) py_dec_out = load_dump(d, "dec_norm_out");
    if (py_dec_out.defined()) {
      std::cout << "[probe] decoder_out cpp[0,0,:6]: ";
      for (int i = 0; i < 6; ++i)
          std::cout << tf_out.decoder_out[0][0][i].item<float>() << " ";
      std::cout << "\n[probe] decoder_out py [0,0,:6]: ";
      for (int i = 0; i < 6; ++i)
          std::cout << py_dec_out[0][0][i].item<float>() << " ";
      std::cout << "\n";
    }
    // Run forward_eval through the public API for comparison.
    auto eval_out = m->forward_eval(inp);
    std::cout << "[stage] forward_eval     shape=" << eval_out.sizes()
              << "  cls slice abs.max=" << eval_out.slice(1, 4).abs().max().item<float>() << "\n";
  }
  // Compare per-tap against Python's `proj_input_*`.
  {
    auto taps = dmodel.forward(inp);   // [B, C, Hg, Wg] × 4
    for (size_t i = 0; i < taps.size(); ++i) {
      char name[32]; std::snprintf(name, sizeof(name), "proj_input_%zu", i);
      auto py = load_dump(d, name);
      if (py.defined()) {
        float diff = max_abs_diff(taps[i].to(torch::kFloat).contiguous(),
                                    py.to(torch::kFloat).contiguous());
        std::cout << "[stage] tap" << i << "  shape=" << taps[i].sizes()
                  << "  cpp_sum=" << taps[i].sum().item<float>()
                  << "  py_sum=" << py.sum().item<float>()
                  << "  max_abs_diff=" << diff << "\n";
      }
    }
  }

  return 0;
}
